@induane Sorry I didn't get a chance to comment before this got merged.  Here are a couple of additional Hypothesis tests I wrote:

```python
from boltons import ioutils
from hypothesis import strategies as st, given
import io
import os
import pytest


def make_spooled_stringio():
    return ioutils.SpooledStringIO(32)


def draw_where(text, data):
    return data.draw(st.integers(min_value=0, max_value=len(text)))


@given(text=st.text(),
       data=st.data())
@pytest.mark.parametrize('make_sio', [
    io.StringIO,
    make_spooled_stringio,
])
def test_seek(text, data, make_sio):
    where = draw_where(text, data)
    s = make_sio()
    s.write(text)
    s.seek(where)
    assert s.read() == text[where:]


@given(text=st.text(),
       data=st.data())
def test_seek_end(text, data):
    where = draw_where(text, data)
    s = make_spooled_stringio()
    s.write(text)
    s.seek(where, os.SEEK_END)
    assert s.read() == text[len(text) - where:]


@given(text=st.text(),
       data=st.data())
def test_seek_cur(text, data):
    where = draw_where(text, data)
    s = make_spooled_stringio()
    s.write(text + text)
    s.seek(len(text))
    s.seek(where, os.SEEK_CUR)
    assert s.read() == text[where:]


@given(text=st.text())
@pytest.mark.parametrize('make_sio', [
    io.StringIO,
    make_spooled_stringio,
])
def test_tell(text, make_sio):
    s = make_sio()
    s.write(text)
    assert s.tell() == len(text)
```

You might be pleased to know that all tests pass :) 

